   * - `"retro"` – retro-inspired pixel art with muted colour palettes
   * - `"8bit"` – strict 8-bit palette and chunky pixels
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (pixels per unit) used when rendering the image.
   * Higher values produce finer pixel grids; lower values produce chunkier
   * pixels. Must be a positive integer.
   */
  pixelDensity?: number;
}

