import { ImageModelV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Provider interface
// ---------------------------------------------------------------------------

/**
 * PixelArt provider interface.
 *
 * This provider only supports image generation — it has no language model,
 * embedding, or video capabilities.
 */
export interface PixelArtProvider {
  readonly specificationVersion: 'v3';

  /**
   * Creates a PixelArt image generation model.
   *
   * @param modelId - The model ID to use (e.g. `"pixelart-v1"`).
   * @param settings - Optional model-level settings such as `size`, `style`,
   *   and `pixelDensity`.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image()`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Provider settings
// ---------------------------------------------------------------------------

/**
 * Settings for creating a PixelArt provider instance.
 */
export interface PixelArtProviderSettings {
  /**
   * Override the base URL for all API requests.
   * Defaults to `"https://api.pixelart.ai/v1"`.
   */
  baseURL?: string;

  /**
   * PixelArt API key. Defaults to the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Additional HTTP headers to include in every request.
   */
  headers?: Record<string, string | undefined>;

  /**
   * Custom `fetch` implementation. Useful for proxies, middleware, or testing.
   */
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Factory function
// ---------------------------------------------------------------------------

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

/**
 * Create a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 * import { generateImage } from 'ai';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { image } = await generateImage({
 *   model: pixelart.image('pixelart-v1', { style: '8bit', pixelDensity: 4 }),
 *   prompt: 'A knight standing in front of a castle',
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? DEFAULT_BASE_URL;

  const getHeaders = () => ({
    Authorization: `Bearer ${loadApiKey({
      apiKey: options.apiKey,
      environmentVariableName: 'PIXELART_API_KEY',
      description: 'PixelArt',
    })}`,
    ...options.headers,
  });

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ): ImageModelV3 =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
  };
}

// ---------------------------------------------------------------------------
// Default instance
// ---------------------------------------------------------------------------

/**
 * Default PixelArt provider instance.
 *
 * Uses the `PIXELART_API_KEY` environment variable for authentication and
 * `https://api.pixelart.ai/v1` as the base URL.
 */
export const pixelart = createPixelArt();

