import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  Resolvable,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Error schema
// ---------------------------------------------------------------------------

const pixelArtErrorSchema = lazySchema(() =>
  zodSchema(
    z.object({
      error: z.object({
        code: z.string(),
        message: z.string(),
      }),
    }),
  ),
);

type PixelArtErrorData = InferSchema<typeof pixelArtErrorSchema>;

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: (data: PixelArtErrorData) => data.error.message,
});

// ---------------------------------------------------------------------------
// Success response schema
// ---------------------------------------------------------------------------

const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z
        .array(
          z.object({
            b64_json: z.string(),
          }),
        )
        .default([]),
      model: z.string().nullish(),
    }),
  ),
);

type PixelArtImageResponse = InferSchema<typeof pixelArtImageResponseSchema>;

// ---------------------------------------------------------------------------
// Provider-specific options schema (passed via providerOptions.pixelart)
// ---------------------------------------------------------------------------

const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The style of pixel art to generate.
       * Overrides the model-level setting.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      /**
       * The pixel density (pixels per unit) for the generated image.
       * Overrides the model-level setting.
       */
      pixelDensity: z.number().int().positive().nullish(),
    }),
  ),
);

type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Model class
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get provider(): string {
    return this.config.provider;
  }

  get maxImagesPerCall(): number {
    return 4;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n = 1,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // PixelArt API does not support image editing
    if (files != null && files.length > 0) {
      throw new Error(
        'PixelArt does not support image editing. ' +
          'Remove the `files` option to generate a new image from a prompt.',
      );
    }

    if (mask != null) {
      throw new Error(
        'PixelArt does not support mask-based image editing. ' +
          'Remove the `mask` option to generate a new image from a prompt.',
      );
    }

    // aspectRatio is not supported by the PixelArt API — emit a warning
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    // Parse per-call provider-specific options
    const pixelArtOptions = (await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    })) as PixelArtImageModelOptions | undefined;

    // Resolve style and pixelDensity: per-call options override model settings
    const style = pixelArtOptions?.style ?? this.settings.style;
    const pixelDensity =
      pixelArtOptions?.pixelDensity ?? this.settings.pixelDensity;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      body.size = size;
    } else if (this.settings.size != null) {
      body.size = this.settings.size;
    }

    if (seed != null) {
      body.seed = seed;
    }

    if (style != null) {
      body.style = style;
    }

    if (pixelDensity != null) {
      body.pixel_density = pixelDensity;
    }

    const { responseHeaders, value: response } =
      await postJsonToApi<PixelArtImageResponse>({
        url: `${this.config.baseURL}/images/generate`,
        headers: combineHeaders(await resolve(this.config.headers), headers),
        body,
        failedResponseHandler: pixelArtFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(
          pixelArtImageResponseSchema,
        ),
        abortSignal,
        fetch: this.config.fetch,
      });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: response.model ?? this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

