export { createPixelArt, pixelart } from './pixelart-provider';
export type {
  PixelArtProvider,
  PixelArtProviderSettings,
} from './pixelart-provider';

export type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

/**
 * The ID of a PixelArt image generation model.
 */
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-retro'
  | (string & {});

/**
 * Settings for a PixelArt image generation model instance.
 * These are model-level defaults that can be overridden per-call
 * via `providerOptions.pixelart`.
 */
export interface PixelArtImageSettings {
  /**
   * The output image size (e.g. "256x256", "512x512", "1024x1024").
   * If not specified the API uses its default size.
   */
  size?: string;

  /**
   * The artistic style of the generated image.
   * - `"pixel"` – classic pixel art style
   * - `"retro"` – retro-inspired pixel art with muted colour palettes
   * - `"8bit"` – strict 8-bit palette and chunky pixels
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (pixels per unit) used when rendering the image.
   * Higher values produce finer pixel grids; lower values produce chunkier
   * pixels. Must be a positive integer.
   */
  pixelDensity?: number;
}
